{"returncode":0,"stdout":"<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>CHO부문 일하는 방식 논의</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
<style>
:root{
  --red:#A50034;--red-mid:#c4003d;--red-light:#f9e6ec;
  --dark:#1a1a1a;--g900:#222;--g700:#4b4b4d;--g500:#787a7d;--g300:#c8c8c8;--g100:#f4f4f4;--white:#fff;
  --yellow:#FBBF24;
  --font:'Noto Sans KR',system-ui,sans-serif;
}
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:var(--font);background:var(--dark);color:var(--white);min-height:100vh;display:flex;flex-direction:column}

/* ── TOP BAR ── */
.top-bar{background:rgba(0,0,0,.4);backdrop-filter:blur(12px);display:flex;align-items:center;justify-content:space-between;padding:0 48px;height:52px;position:fixed;top:0;left:0;right:0;z-index:200;border-bottom:1px solid rgba(255,255,255,.06)}
.tb-left{display:flex;align-items:center;gap:14px}
.lg-logo{font-size:19px;font-weight:700;color:var(--red);letter-spacing:-0.5px}
.tb-div{width:1px;height:16px;background:rgba(255,255,255,.15)}
.tb-title{font-size:15px;color:rgba(255,255,255,.45);font-weight:300;letter-spacing:.04em}
.tb-badge{font-size:12px;font-weight:700;padding:3px 10px;border:1px solid var(--yellow);color:var(--yellow);border-radius:2px;letter-spacing:.08em}

/* ── HERO ── */
.hero{margin-top:52px;padding:80px 48px 60px;text-align:center;background:linear-gradient(165deg,#0d0d0d 0%,#1a1a2e 40%,#16213e 70%,#0f3460 100%);position:relative;overflow:hidden}
.hero::before{content:'';position:absolute;top:-50%;left:-10%;width:120%;height:200%;background:radial-gradient(ellipse at 30% 20%,rgba(165,0,52,.12) 0%,transparent 60%);pointer-events:none}
.hero-eyebrow{font-size:14px;font-weight:700;color:rgba(255,255,255,1);letter-spacing:.2em;text-transform:uppercase;margin-bottom:20px;position:relative}
.hero-title{font-size:clamp(36px,5.5vw,56px);font-weight:900;line-height:1.2;letter-spacing:-1.5px;margin-bottom:16px;position:relative}
.hero-title span{color:var(--yellow)}
.hero-desc{font-size:17px;color:rgba(255,255,255,.5);line-height:1.8;max-width:700px;margin:0 auto;position:relative}

/* ── MENU CARDS ── */
.menu-section{padding:0 48px 80px;margin-top:-20px;position:relative;z-index:10}
.menu-label{font-size:13px;font-weight:700;color:#fff;letter-spacing:.15em;text-transform:uppercase;text-align:center;margin-bottom:28px;opacity:.8}
.menu-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:24px;max-width:1280px;margin:0 auto}

.menu-card{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-radius:20px;padding:0;overflow:hidden;cursor:pointer;transition:all .25s;display:flex;flex-direction:column;text-decoration:none;color:inherit;position:relative}
.menu-card:hover{transform:translateY(-8px);box-shadow:0 20px 60px rgba(165,0,52,.15);border-color:rgba(165,0,52,.3)}
.menu-card:hover .mc-top{background:var(--red)}
.menu-card:hover .mc-num{color:var(--white)}
.menu-card:hover .mc-icon{color:var(--white);opacity:1}
.menu-card:hover .mc-arrow{opacity:1;transform:translateX(0)}

.mc-top{height:6px;background:rgba(255,255,255,.08);transition:background .25s}
.mc-body{padding:36px 32px 32px;flex:1;display:flex;flex-direction:column}
.mc-num-row{display:flex;align-items:center;justify-content:space-between;margin-bottom:20px}
.mc-num{font-size:52px;font-weight:900;color:#fff;line-height:1;transition:color .25s;letter-spacing:-2px}
.mc-icon{font-size:30px;color:var(--red);opacity:.5;transition:all .25s}
.mc-title{font-size:22px;font-weight:700;color:var(--white);line-height:1.35;margin-bottom:12px;letter-spacing:-.3px}
.mc-desc{font-size:16px;color:rgba(255,255,255,.85);line-height:1.7;flex:1}
.mc-footer{display:none}

/* Reference submenu */
.ref-submenu{list-style:none;padding:0;margin-top:16px;display:block}
.ref-item{padding:8px 0;border-top:1px solid rgba(255,255,255,.06)}
.ref-item:first-child{border-top:none}
.ref-link{color:#fff;text-decoration:none;font-size:14px;display:flex;align-items:center;gap:8px;transition:color .2s;opacity:.9}
.ref-link:hover{color:var(--red)}
.ref-link i{font-size:12px}

/* ── STATS ── */
.stats-row{display:flex;justify-content:center;gap:48px;padding:40px 48px;border-top:1px solid rgba(255,255,255,.05)}
.stat-item{text-align:center}
.stat-num{font-size:36px;font-weight:900;color:var(--white);line-height:1;letter-spacing:-1px}
.stat-num span{color:var(--yellow);font-size:20px}
.stat-label{font-size:14px;color:#fff;margin-top:6px;opacity:.85}

/* ── FOOTER ── */
.landing-footer{text-align:center;padding:28px 48px;border-top:1px solid rgba(255,255,255,.05);margin-top:auto}
.lf-logo{font-weight:700;color:rgba(255,255,255,.08);font-size:15px;letter-spacing:.3em;text-transform:uppercase}
.lf-copy{font-size:13px;color:#fff;margin-top:6px;opacity:.3}

/* ── RESPONSIVE ── */
@media(max-width:1100px){
  .menu-grid{grid-template-columns:repeat(2,1fr);max-width:640px}
}
@media(max-width:600px){
  .menu-grid{grid-template-columns:1fr;max-width:480px}
  .hero{padding:60px 24px 40px}
  .menu-section{padding:0 24px 60px}
  .stats-row{gap:28px;flex-wrap:wrap}
}
</style>
</head>
<body>

<!-- TOP BAR -->
<div class="top-bar">
  <div class="tb-left">
    <div class="lg-logo">LG</div>
    <div class="tb-div"></div>
    <div class="tb-title">CHO부문 일하는 방식 논의</div>
  </div>
  <div class="tb-badge">함께 만들고 함께 지키는 약속</div>
</div>

<!-- HERO -->
<section class="hero">
  <div class="hero-eyebrow">CHO부문 전사 인원/인건비 W/S (3/25)</div>
  <h1 class="hero-title"> <span> CHO부문 일하는 방식 변화 논의<br></span></h1>
  <p class="hero-desc">매일 몸으로 느끼는 일하는 방식의 변화 <br> <span style="color: var(--yellow); font-weight: 500;">Way of working for a world-class HR organization</span> </p>
</section>

<!-- MENU CARDS -->
<section class="menu-section">
  <div class="menu-label">Select a Module</div>
  <div class="menu-grid">

    <!-- Card 1: 변화의 방향성 제안 -->
    <a class="menu-card" href="HR_VIBE_Direction.html">
      <div class="mc-top"></div>
      <div class="mc-body">
        <div class="mc-num-row">
          <div class="mc-num">01</div>
          <div class="mc-icon"><i class="fa-solid fa-compass"></i></div>
        </div>
        <div class="mc-title">변화의 방향</div>
        <div class="mc-desc"> CHO부문의 일하는 방식 변화 방향성을 명확하게 합니다. </div>
        <div class="mc-footer">
          <div class="mc-tags">
            <span class="mc-tag mc-tag-red">4 VIBE</span>
            <span class="mc-tag mc-tag-blue">Before→After</span>
            <span class="mc-tag mc-tag-green">8 원칙</span>
          </div>
          <div class="mc-arrow"><i class="fa-solid fa-arrow-right"></i></div>
        </div>
      </div>
    </a>

    <!-- Card 2: Ground Rule -->
    <a class="menu-card" href="HR_VIBE_GroundRule.html">
      <div class="mc-top"></div>
      <div class="mc-body">
        <div class="mc-num-row">
          <div class="mc-num">02</div>
          <div class="mc-icon"><i class="fa-solid fa-handshake"></i></div>
        </div>
        <div class="mc-title">Ground Rules</div>
        <div class="mc-desc">우리가 함께 지킬 Ground Rules. CHO부문의 구체적 행동, 실행 원칙입니다.</div>
        <div class="mc-footer">
          <div class="mc-tags">
            <span class="mc-tag mc-tag-red">8 Rules</span>
            <span class="mc-tag mc-tag-blue">구체적 실행</span>
            <span class="mc-tag mc-tag-green">언제·어디·무엇·어떻게</span>
          </div>
          <div class="mc-arrow"><i class="fa-solid fa-arrow-right"></i></div>
        </div>
      </div>
    </a>

    <!-- Card 3: 향후 추진방향 -->
    <a class="menu-card" href="Digital_Transformation_Roadmap.html">
      <div class="mc-top"></div>
      <div class="mc-body">
        <div class="mc-num-row">
          <div class="mc-num">03</div>
          <div class="mc-icon"><i class="fa-solid fa-road"></i></div>
        </div>
        <div class="mc-title">향후 추진방향</div>
        <div class="mc-desc"> 조직에 스며드는 방법. 함께 하는 변화를 지금부터 준비합니다. </div>
        <div class="mc-footer">
          <div class="mc-tags">
            <span class="mc-tag mc-tag-red">4 Phases</span>
            <span class="mc-tag mc-tag-blue">2026. 3~</span>
            <span class="mc-tag mc-tag-yellow">점진적 확대</span>
          </div>
          <div class="mc-arrow"><i class="fa-solid fa-arrow-right"></i></div>
        </div>
      </div>
    </a>

    <!-- Card 4: 비고 및 참고자료 -->
    <div class="menu-card" onclick="this.classList.toggle('expanded')" style="cursor:default">
      <div class="mc-top"></div>
      <div class="mc-body">
        <div class="mc-num-row">
          <div class="mc-num">04</div>
          <div class="mc-icon"><i class="fa-solid fa-folder-open"></i></div>
        </div>
        <div class="mc-title">비고 및 참고자료</div>
        <div class="mc-desc">실행을 위한 가이드와 참고 자료를 확인하세요.</div>
        <ul class="ref-submenu">
          <li class="ref-item"><a href="guide.html" class="ref-link"><i class="fa-solid fa-circle"></i> Teams 협업 마스터 가이드</a></li>
          <li class="ref-item"><a href="https://lgeteams-my.sharepoint.com/:p:/g/personal/sangho1_shin_lge_com/IQAakThjsK_5SbyEDkRuh8nrAW_rdr0Rs9-Ij_cdzRX2QOM?e=0xccqR" target="_blank" class="ref-link"><i class="fa-solid fa-download"></i> 담당 타운홀 미팅 가이드</a></li>
          <li class="ref-item"><a href="https://lgeteams-my.sharepoint.com/:b:/g/personal/sangho1_shin_lge_com/IQBTlTa3d-cZSI3cHHllf2LHAZ3OzJ9f6kTF6FWDsIp0Y6o?e=NHfkjW" target="_blank" class="ref-link"><i class="fa-solid fa-download"></i> 1on1 가이드 (리더용)</a></li>
          <li class="ref-item"><a href="https://lgeteams-my.sharepoint.com/:b:/g/personal/sangho1_shin_lge_com/IQDz4Dq1hGOARoLyIRxeIRTAATxyIR6cbxubz4bVTHJxvc0?e=7PXGdm" target="_blank" class="ref-link"><i class="fa-solid fa-download"></i> 1on1 가이드 (구성원용)</a></li>
        </ul>
      </div>
    </div>

  </div>
</section>

<!-- STATS -->
<div class="stats-row">
  <div class="stat-item"><div class="stat-num">4</div><div class="stat-label">VIBE 원칙</div></div>
  <div class="stat-item"><div class="stat-num">8</div><div class="stat-label">Ground Rules</div></div>
  <div class="stat-item"><div class="stat-num">3</div><div class="stat-label">Rollout Phases</div></div>
  <div class="stat-item"><div class="stat-num">4<span></span></div><div class="stat-label">참고자료</div></div>
</div>

<!-- FOOTER -->
<footer class="landing-footer">
  <div class="lf-logo">LG Life's Good</div>
  <div class="lf-copy">CHO부문 일하는 방식 논의 2026</div>
</footer>

</body>
</html>
