  --vibe-i: #1D4ED8;
  --vibe-b: #059669;
  --vibe-e: #7C3AED;

  --silo-gray: #6B7280;
  --silo-border: #9CA3AF;
  --silo-dark: #4B5563;

  --font: 'Noto Sans KR', system-ui, sans-serif;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font);
  background: #F1F5F9;
  color: #1F2937;
  line-height: 1.65;
}

/* Top Bar */
.top-bar {
  background: rgba(0,0,0,.85);
  backdrop-filter: blur(12px);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 48px;
  height: 52px;
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 200;
