}

.tb-left {
  display: flex;
  align-items: center;
  gap: 14px;
}

.lg-logo {
  font-size: 19px;
  font-weight: 700;
  color: var(--red);
  letter-spacing: -0.5px;
}

.tb-div {
  width: 1px;
  height: 16px;
  background: rgba(255,255,255,.15);
}

.tb-title {
  font-size: 15px;
  color: rgba(255,255,255,.65);
  font-weight: 300;
  letter-spacing: .04em;
}

.tb-back {
  font-size: 14px;
  color: rgba(255,255,255,.45);
  text-decoration: none;
  transition: color 0.2s;
  display: flex;
  align-items: center;
  gap: 6px;
}

.tb-back:hover {
  color: var(--accent-yellow);
}

/* Hero */
.hero {
  margin-top: 52px;
  padding: 80px 48px 60px;
  text-align: center;
  background: linear-gradient(165deg, #0d0d0d 0%, #1a1a2e 40%, #16213e 70%, #0f3460 100%);
  position: relative;
  overflow: hidden;
  color: #fff;
}

.hero::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -10%;
  width: 120%;
  height: 200%;
  background: radial-gradient(ellipse at 30% 20%, rgba(165,0,52,.12) 0%, transparent 60%);
  pointer-events: none;
}

.hero-eyebrow {
  font-size: 14px;
  font-weight: 700;
  color: rgba(255,255,255,1);
  letter-spacing: .2em;
  text-transform: uppercase;
  margin-bottom: 20px;
  position: relative;
}

.hero-title {
  font-size: clamp(36px, 5.5vw, 56px);
  font-weight: 900;
  line-height: 1.3;
  letter-spacing: -1.5px;
  margin-bottom: 12px;
  position: relative;
  color: var(--accent-yellow);
}

.hero-subtitle {
  font-size: clamp(29px, 4.4vw, 45px);
  font-weight: 700;
  line-height: 1.3;
  letter-spacing: -0.5px;
  margin-bottom: 16px;
  position: relative;
  color: #ffffff;
