<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>CHO부문 Ground Rules</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
<style>
:root {
  --red: #A50034;
  --red-light: #f9e6ec;
  --yellow: #FBBF24;
  --text-dark: #1F2937;
  --bg-light: #F3F4F6;
  --font: 'Noto Sans KR', system-ui, sans-serif;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font);
  background: #F9FAFB;
  color: #1F2937;
  line-height: 1.65;
}

/* Top Bar */
.top-bar {
  background: rgba(0,0,0,.85);
  backdrop-filter: blur(12px);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 48px;
  height: 52px;
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 200;
  border-bottom: 1px solid rgba(255,255,255,.06);
}

.tb-left {
  display: flex;
  align-items: center;
  gap: 14px;
}

.lg-logo {
  font-size: 19px;
  font-weight: 700;
  color: var(--red);
  letter-spacing: -0.5px;
}

.tb-div {
  width: 1px;
  height: 16px;
  background: rgba(255,255,255,.15);
}

.tb-title {
  font-size: 15px;
  color: rgba(255,255,255,.65);
  font-weight: 300;
  letter-spacing: .04em;
}

.tb-back {
  font-size: 14px;
  color: rgba(255,255,255,.45);
  text-decoration: none;
  transition: color 0.2s;
  display: flex;
  align-items: center;
  gap: 6px;
}

.tb-back:hover {
  color: var(--yellow);
}

/* Hero */
.hero {
  margin-top: 52px;
  padding: 80px 48px 80px;
  text-align: center;
  background: linear-gradient(135deg, #1a1a2e 0%, var(--red) 100%);
  position: relative;
  overflow: hidden;
  color: #fff;
}

.hero::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -10%;
  width: 120%;
  height: 200%;
  background: radial-gradient(ellipse at 50% 50%, rgba(255,255,255,.08) 0%, transparent 60%);
  pointer-events: none;
}

.hero-eyebrow {
  font-size: 14px;
  font-weight: 700;
  color: rgba(255,255,255,.7);
  letter-spacing: .2em;
  text-transform: uppercase;
  margin-bottom: 20px;
  position: relative;
}

.hero-title {
  font-size: clamp(32px, 5vw, 48px);
  font-weight: 900;
  line-height: 1.2;
  letter-spacing: -1px;
  margin-bottom: 16px;
  position: relative;
}

.hero-desc {
  font-size: 17px;
  color: rgba(255,255,255,.75);
  line-height: 1.8;
  max-width: 700px;
  margin: 0 auto;
  position: relative;
}


/* Main Content */
.main-content {
  max-width: 1200px;
  margin: 0 auto;
  padding: 80px 48px 80px;
}

/* Content Header */
.content-header {
  text-align: center;
  margin-bottom: 60px;
}

.content-title {
  font-size: 36px;
  font-weight: 900;
  color: var(--red);
  letter-spacing: -1px;
}



/* Principles Section */
.principles-grid {
  display: grid;
  gap: 32px;
}

.principle-card {
  background: #fff;
  border-radius: 20px;
  padding: 40px;
  box-shadow: 0 8px 32px rgba(0,0,0,.08);
  border: 2px solid var(--red-light);
}

.principle-header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 28px;
  padding-bottom: 20px;
  border-bottom: 2px solid var(--red-light);
}

.principle-number {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  background: var(--red);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  font-weight: 900;
  flex-shrink: 0;
}

.principle-title {
  font-size: 24px;
  font-weight: 900;
  color: #1F2937;
  line-height: 1.3;
}

.do-dont-container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
  margin-bottom: 24px;
}

.do-box, .dont-box {
  padding: 24px;
  border-radius: 12px;
}

.do-box {
  background: linear-gradient(135deg, #ecfdf5 0%, #d1fae5 100%);
  border: 2px solid #10b981;
}

.dont-box {
  background: linear-gradient(135deg, #fef2f2 0%, #fee2e2 100%);
  border: 2px solid #ef4444;
}

.do-dont-label {
  font-size: 14px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: .1em;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.do-box .do-dont-label {
  color: #047857;
}

.dont-box .do-dont-label {
  color: #dc2626;
}

.do-dont-label i {
  font-size: 18px;
}

.do-dont-text {
  font-size: 15px;
  line-height: 1.7;
  color: #1F2937;
  font-weight: 500;
}

.context-box {
  background: linear-gradient(135deg, #fffbeb 0%, #fef3c7 100%);
  border-left: 4px solid var(--yellow);
  padding: 20px 24px;
  border-radius: 12px;
}

.context-label {
  font-size: 14px;
  font-weight: 700;
  color: #92400e;
  margin-bottom: 8px;
  text-transform: uppercase;
  letter-spacing: .08em;
}

.context-text {
  font-size: 15px;
  color: #78350f;
  line-height: 1.7;
}

/* VIBE Category Section - 2 Column Layout */
.vibe-category {
  margin-bottom: 80px;
  display: grid;
  grid-template-columns: 180px 1fr;
  gap: 32px;
  align-items: stretch;
}

.vibe-category-sidebar {
  background: linear-gradient(135deg, #F3F4F6 0%, #E5E7EB 100%);
  border-radius: 16px;
  padding: 28px 20px;
  box-shadow: 0 4px 16px rgba(0,0,0,.06);
  border: 2px solid #D1D5DB;
  text-align: center;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.vibe-category-title {
  font-size: 20px;
  font-weight: 900;
  margin-bottom: 8px;
  letter-spacing: -0.5px;
  color: #4B5563;
  line-height: 1.3;
}

.vibe-category-subtitle {
  font-size: 16px;
  font-weight: 400;
  color: #6B7280;
}

.vibe-category-subtitle span {
  font-weight: 700;
  color: var(--red);
}

/* Action Principle Cards */
.action-principles-grid {
  display: grid;
  gap: 24px;
}

.action-card {
  background: #fff;
  border-radius: 20px;
  padding: 32px;
  box-shadow: 0 8px 32px rgba(0,0,0,.08);
  border: 2px solid var(--red-light);
  transition: all 0.3s ease;
}

.action-card:hover {
  box-shadow: 0 12px 48px rgba(0,0,0,.12);
  transform: translateY(-2px);
}

.action-card-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--red);
  margin-bottom: 16px;
  line-height: 1.4;
}

.action-card-desc {
  font-size: 16px;
  color: #1F2937;
  line-height: 1.8;
  margin-bottom: 20px;
}

/* DO/DON'T/WHY Sections in Action Card */
.action-sections {
  display: flex;
  flex-direction: column;
  margin-top: 20px;
  border-top: 1px solid #E5E7EB;
}

.action-section {
  padding: 16px 0;
  border-bottom: 1px solid #E5E7EB;
  display: flex;
  align-items: flex-start;
  gap: 12px;
}

.action-section:last-child {
  border-bottom: none;
}

.action-section-label {
  font-size: 14px;
  font-weight: 700;
  flex-shrink: 0;
  color: #4B5563;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  min-width: 70px;
  display: inline-block;
}

.action-section-divider {
  color: #D1D5DB;
  flex-shrink: 0;
  font-weight: 300;
}

.action-section-text {
  font-size: 15px;
  line-height: 1.7;
  color: #1F2937;
  flex: 1;
}

