// ── API CALL ──
async function generateHTML() {
  if (state.isLoading) return;

  const title = document.getElementById('f-title').value.trim();
  const content = document.getElementById('f-content').value.trim();

  if (!title) { showToast('페이지 제목을 입력해주세요'); return; }
  if (!content) { showToast('콘텐츠를 입력해주세요'); return; }

  state.isLoading = true;
  setLoadingState(true);

  const userPrompt = buildUserPrompt();

  const steps = [
    '디자인 시스템 적용 중...',
    '레이아웃 구조 설계 중...',
    '컴포넌트 렌더링 중...',
    '반응형 CSS 최적화 중...',
    '최종 HTML 완성 중...',
  ];
  let stepIdx = 0;
  const stepInterval = setInterval(() => {
    stepIdx = (stepIdx + 1) % steps.length;
    document.getElementById('loading-step').textContent = steps[stepIdx];
  }, 1800);

  try {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 8000,
        system: buildSystemPrompt(state.pageType, state.accentColor, state.theme),
        messages: [{ role: 'user', content: userPrompt }]
      })
    });

    if (!response.ok) {
      const err = await response.json().catch(() => ({}));
      throw new Error(err.error?.message || `API Error ${response.status}`);
    }

    const data = await response.json();
    const rawText = data.content?.find(b => b.type === 'text')?.text || '';

    // Extract HTML
    let html = rawText.trim();
    const fenceMatch = html.match(/```html?\s*([\s\S]+?)```/i);
    if (fenceMatch) html = fenceMatch[1].trim();
    if (!html.startsWith('<!DOCTYPE') && !html.startsWith('<html')) {
      const doctypeIdx = html.indexOf('<!DOCTYPE');
      const htmlIdx = html.indexOf('<html');
      const start = doctypeIdx >= 0 ? doctypeIdx : htmlIdx;
      if (start >= 0) html = html.slice(start);
    }

    if (!html.includes('<html')) throw new Error('HTML 생성에 실패했습니다. 다시 시도해주세요.');

    state.generatedHTML = html;
    renderPreview(html);
    addHistory(title, state.pageType);

    // Switch to preview tab
    switchTab('preview');
    document.getElementById('btn-download').style.display = '';
    document.getElementById('btn-copy').style.display = '';

  } catch (err) {
    showToast('생성 오류: ' + err.message);
    console.error(err);
  } finally {
    clearInterval(stepInterval);
    state.isLoading = false;
    setLoadingState(false);
  }
}

function buildUserPrompt() {
  const title = document.getElementById('f-title').value.trim();
  const subtitle = document.getElementById('f-subtitle').value.trim();
  const eyebrow = document.getElementById('f-eyebrow').value.trim();
  const org = document.getElementById('f-org').value.trim();
  const content = document.getElementById('f-content').value.trim();
  const backUrl = document.getElementById('f-backurl').value.trim();
  const extra = document.getElementById('f-extra').value.trim();

  let prompt = `다음 정보를 기반으로 LG CHO부문 HTML 페이지를 생성해주세요.

# 기본 정보
- 페이지 제목: ${title}
${subtitle ? `- 부제목: ${subtitle}` : ''}
${eyebrow ? `- 이어브로우: ${eyebrow}` : ''}
- 조직명: ${org || 'LG PRI CHO부문'}
${backUrl ? `- 뒤로가기 링크: ${backUrl}` : ''}

# 콘텐츠
${content}`;

  if (extra) {
    prompt += `\n\n# 추가 지시사항\n${extra}`;
  }

  return prompt;
}

// ── UI FUNCTIONS ──
function setLoadingState(loading) {
  const btn = document.getElementById('btn-generate');
  const overlay = document.getElementById('loading-overlay');

  if (loading) {
    btn.classList.add('loading');
    btn.disabled = true;
    overlay.classList.add('visible');
    document.getElementById('empty-state').style.display = 'none';
    // Reset loading bar animation
    const bar = document.getElementById('loading-bar');
    bar.style.animation = 'none';
    bar.offsetHeight; // reflow
    bar.style.animation = '';
  } else {
    btn.classList.remove('loading');
    btn.disabled = false;
    overlay.classList.remove('visible');
  }
}

function renderPreview(html) {
  const frame = document.getElementById('preview-frame');
  const codeContent = document.getElementById('code-content');

  frame.style.display = 'block';
  frame.srcdoc = html;

  codeContent.textContent = html;

  document.getElementById('empty-state').style.display = 'none';
}

function switchTab(tab) {
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelector(`.tab-btn[data-tab="${tab}"]`)?.classList.add('active');

  const frame = document.getElementById('preview-frame');
  const code = document.getElementById('code-view');
  const examples = document.getElementById('examples-panel');
  const empty = document.getElementById('empty-state');

  frame.style.display = 'none';
  code.style.display = 'none';
  examples.classList.remove('visible');
  empty.style.display = 'none';

  if (tab === 'preview') {
    if (state.generatedHTML) frame.style.display = 'block';
    else empty.style.display = 'flex';
  } else if (tab === 'code') {
    if (state.generatedHTML) code.style.display = 'block';
    else empty.style.display = 'flex';
  } else if (tab === 'examples') {
    examples.classList.add('visible');
  }
}

function addHistory(title, type) {
  const icons = { portal: 'table-cells-large', content: 'scroll', roadmap: 'road', guide: 'book-open' };
  const typeLabels = { portal: 'PORTAL', content: 'CONTENT', roadmap: 'ROADMAP', guide: 'GUIDE' };

  state.history.unshift({ title, type, html: state.generatedHTML });
  if (state.history.length > 5) state.history.pop();

  const list = document.getElementById('history-list');
  list.innerHTML = state.history.map((h, i) => `
    <div class="history-item" onclick="loadHistory(${i})">
      <i class="fa-solid fa-${icons[h.type] || 'file'} hi-icon"></i>
      <span class="hi-text">${h.title}</span>
      <span class="hi-type">${typeLabels[h.type] || ''}</span>
    </div>
  `).join('');
}

function loadHistory(idx) {
  const h = state.history[idx];
  if (!h) return;
  state.generatedHTML = h.html;
  renderPreview(h.html);
  switchTab('preview');
  document.getElementById('btn-download').style.display = '';
  document.getElementById('btn-copy').style.display = '';
}

function showToast(msg) {
  const toast = document.getElementById('toast');
  toast.textContent = msg;
  toast.classList.add('visible');
  setTimeout(() => toast.classList.remove('visible'), 3500);
}

function downloadHTML() {
  if (!state.generatedHTML) return;
  const title = document.getElementById('f-title').value.trim() || 'cho_page';
  const filename = title.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9가-힣_-]/g, '') + '.html';
  const blob = new Blob([state.generatedHTML], { type: 'text/html;charset=utf-8' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = filename;
  a.click();
  URL.revokeObjectURL(a.href);
}

function copyHTML() {
  if (!state.generatedHTML) return;
  navigator.clipboard.writeText(state.generatedHTML).then(() => {
    showToast('클립보드에 복사되었습니다');
  }).catch(() => {
    showToast('복사 실패: 직접 코드 탭에서 선택해주세요');
  });
}

function fillExample(ex) {
  // Set type
  document.querySelectorAll('.type-btn').forEach(b => b.classList.remove('active'));
  document.querySelector(`.type-btn[data-type="${ex.type}"]`)?.classList.add('active');
  state.pageType = ex.type;

  // Fill content
  document.getElementById('f-content').value = ex.content;
  document.getElementById('f-title').value = ex.title;
  updateCharCounter();

  // Switch to input view
  switchTab('preview');
}

function updateCharCounter() {
  const val = document.getElementById('f-content').value;
  document.getElementById('char-counter').textContent = val.length.toLocaleString() + '자';
}

function buildExamplesGrid() {
  const grid = document.getElementById('ex-grid');
  const icons = { portal: 'table-cells-large', content: 'scroll', roadmap: 'road', guide: 'book-open' };
  grid.innerHTML = EXAMPLES.map((ex, i) => `
    <div class="ex-card" onclick="fillExample(examplesData[${i}])">
      <div class="ex-card-label"><i class="fa-solid fa-${icons[ex.type]}"></i> ${ex.label}</div>
      <div class="ex-card-title">${ex.title}</div>
      <div class="ex-card-desc">${ex.desc}</div>
      <div class="ex-use-btn"><i class="fa-solid fa-arrow-right"></i> 이 예시 사용하기</div>
    </div>
  `).join('');
}

// expose to global
window.examplesData = EXAMPLES;
window.loadHistory = loadHistory;
window.fillExample = fillExample;

// ── EVENT LISTENERS ──
document.addEventListener('DOMContentLoaded', () => {

  // Build examples
  buildExamplesGrid();

  // Type buttons
  document.querySelectorAll('.type-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.type-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      state.pageType = btn.dataset.type;
    });
  });

  // Tab buttons
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => switchTab(btn.dataset.tab));
  });

  // Generate button
  document.getElementById('btn-generate').addEventListener('click', generateHTML);

  // Download button
  document.getElementById('btn-download').addEventListener('click', downloadHTML);

  // Copy button
  document.getElementById('btn-copy').addEventListener('click', copyHTML);

  // Advanced toggle
  document.getElementById('advanced-toggle').addEventListener('click', function() {
    this.classList.toggle('open');
    document.getElementById('advanced-panel').classList.toggle('open');
  });

  // Color picker
  document.querySelectorAll('.color-dot').forEach(dot => {
    dot.addEventListener('click', () => {
      document.querySelectorAll('.color-dot').forEach(d => d.classList.remove('active'));
      dot.classList.add('active');
      state.accentColor = dot.dataset.color;
    });
  });

  // Theme select
  document.getElementById('f-theme').addEventListener('change', function() {
    state.theme = this.value;
  });

  // Char counter
  document.getElementById('f-content').addEventListener('input', updateCharCounter);

  // Enter key on title
  document.getElementById('f-title').addEventListener('keydown', e => {
    if (e.key === 'Enter') generateHTML();
  });
});
</script>
</body>
</html>
