// ── COMPONENT ──
export default function LGCHOAgent() {
  const [pageType, setPageType] = useState("portal");
  const [title, setTitle] = useState("");
  const [subtitle, setSubtitle] = useState("");
  const [eyebrow, setEyebrow] = useState("");
  const [org, setOrg] = useState("LG PRI CHO부문");
  const [content, setContent] = useState("");
  const [backUrl, setBackUrl] = useState("");
  const [extra, setExtra] = useState("");
  const [accentColor, setAccentColor] = useState("#A50034");
  const [theme, setTheme] = useState("dark-blue");
  const [activeTab, setActiveTab] = useState("preview");
  const [generatedHTML, setGeneratedHTML] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState("");
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [history, setHistory] = useState([]);
  const [errorMsg, setErrorMsg] = useState("");
  const iframeRef = useRef(null);

  // ── GENERATE ──
  const generate = useCallback(async () => {
    if (isLoading) return;
    if (!title.trim()) { setErrorMsg("페이지 제목을 입력해주세요"); setTimeout(() => setErrorMsg(""), 3000); return; }
    if (!content.trim()) { setErrorMsg("콘텐츠를 입력해주세요"); setTimeout(() => setErrorMsg(""), 3000); return; }

    setIsLoading(true);
    setErrorMsg("");

    const steps = [
      "디자인 시스템 적용 중...",
      "레이아웃 구조 설계 중...",
      "컴포넌트 렌더링 중...",
      "반응형 CSS 최적화 중...",
      "최종 HTML 완성 중...",
    ];
    let si = 0;
    setLoadingMsg(steps[0]);
    const interval = setInterval(() => {
      si = (si + 1) % steps.length;
      setLoadingMsg(steps[si]);
    }, 1600);

    const userPrompt = `다음 정보로 LG CHO부문 HTML 페이지를 생성해주세요.

# 기본 정보
- 페이지 제목: ${title}
${subtitle ? `- 부제목: ${subtitle}` : ""}
${eyebrow ? `- 이어브로우: ${eyebrow}` : ""}
- 조직명: ${org || "LG PRI CHO부문"}
${backUrl ? `- 뒤로가기 링크: ${backUrl}` : ""}

# 콘텐츠
${content}
${extra ? `\n# 추가 지시사항\n${extra}` : ""}`;

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 8000,
          system: buildSystemPrompt(pageType, accentColor, theme),
          messages: [{ role: "user", content: userPrompt }],
        }),
      });

      if (!res.ok) {
        const e = await res.json().catch(() => ({}));
        throw new Error(e.error?.message || `API Error ${res.status}`);
      }

      const data = await res.json();
      let raw = data.content?.find(b => b.type === "text")?.text || "";
      raw = raw.trim();

      // Extract HTML
      const fenceMatch = raw.match(/```html?\s*([\s\S]+?)```/i);
      if (fenceMatch) raw = fenceMatch[1].trim();
      const dIdx = raw.indexOf("<!DOCTYPE");
      const hIdx = raw.indexOf("<html");
      const start = dIdx >= 0 ? dIdx : hIdx;
      if (start > 0) raw = raw.slice(start);

      if (!raw.includes("<html")) throw new Error("HTML 생성 실패. 다시 시도해주세요.");

      setGeneratedHTML(raw);
      setActiveTab("preview");
      setHistory(prev => [{ title, type: pageType, html: raw }, ...prev.slice(0, 4)]);

      // Inject into iframe
      setTimeout(() => {
        if (iframeRef.current) iframeRef.current.srcdoc = raw;
      }, 50);

    } catch (err) {
      setErrorMsg("오류: " + err.message);
      setTimeout(() => setErrorMsg(""), 5000);
    } finally {
      clearInterval(interval);
      setIsLoading(false);
      setLoadingMsg("");
    }
  }, [isLoading, pageType, title, subtitle, eyebrow, org, content, backUrl, extra, accentColor, theme]);

  // Tab switch handler
  const switchTab = (tab) => {
    setActiveTab(tab);
    if (tab === "preview" && generatedHTML && iframeRef.current) {
      setTimeout(() => { if (iframeRef.current) iframeRef.current.srcdoc = generatedHTML; }, 50);
    }
  };

  // Download
  const download = () => {
    if (!generatedHTML) return;
    const fname = (title || "cho_page").replace(/\s+/g, "_").replace(/[^a-zA-Z0-9가-힣_-]/g, "") + ".html";
    const blob = new Blob([generatedHTML], { type: "text/html;charset=utf-8" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = fname;
    a.click();
    URL.revokeObjectURL(a.href);
  };

  // Fill example
  const fillExample = (ex) => {
    setPageType(ex.type);
    setTitle(ex.title);
    setSubtitle(ex.subtitle || "");
    setEyebrow(ex.eyebrow || "");
    setOrg(ex.org || "LG PRI CHO부문");
    setContent(ex.content);
  };

  const ACCENTS = ["#A50034","#1D4ED8","#059669","#7C3AED","#D97706","#0891B2"];
  const hasOutput = !!generatedHTML;

  return (
    <div style={css.app}>

      {/* TOPBAR */}
      <div style={css.topbar}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <span style={{ fontSize: 18, fontWeight: 900, color: T.red, letterSpacing: "-0.5px" }}>LG</span>
          <span style={{ width: 1, height: 14, background: "rgba(255,255,255,.15)", display: "inline-block" }}></span>
          <span style={{ fontSize: 13, color: "rgba(255,255,255,.45)", fontWeight: 300, letterSpacing: ".05em" }}>
            CHO부문 HTML Generator
          </span>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{
            fontSize: 10, fontWeight: 700, padding: "3px 10px",
            background: "linear-gradient(135deg,#A50034,#ff4d6d)",
            borderRadius: 20, letterSpacing: ".08em",
          }}>AI AGENT</span>
          <span style={{ fontSize: 10, color: "rgba(255,255,255,.3)", letterSpacing: ".04em" }}>No API Key Required</span>
        </div>
      </div>

      {/* BODY */}
      <div style={css.body}>

        {/* SIDEBAR */}
        <div style={css.sidebar}>
          <div style={css.sidebarScroll}>

            {/* Page Type */}
            <div style={css.sectionLabel}>페이지 유형</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginBottom: 16 }}>
              {PAGE_TYPES.map(pt => (
                <button
                  key={pt.id}
                  onClick={() => setPageType(pt.id)}
                  style={{
                    padding: "9px 6px",
                    background: pageType === pt.id ? "rgba(165,0,52,.15)" : "rgba(255,255,255,.04)",
                    border: `1px solid ${pageType === pt.id ? "rgba(165,0,52,.5)" : "rgba(255,255,255,.08)"}`,
                    borderRadius: 10, cursor: "pointer", textAlign: "center",
                    color: pageType === pt.id ? "#fff" : "rgba(255,255,255,.5)",
                    fontFamily: "'Noto Sans KR', system-ui, sans-serif",
                    transition: "all .2s",
                  }}
                >
                  <div style={{ fontSize: 15, marginBottom: 3, color: T.red, opacity: pageType === pt.id ? 1 : .6 }}>{pt.icon}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: ".02em" }}>{pt.label}</div>
                </button>
              ))}
            </div>

            {/* Basic Fields */}
            <div style={css.sectionLabel}>기본 정보</div>
            <div style={css.fieldLabel}>페이지 제목 <span style={{ color: T.red }}>*</span></div>
            <input style={css.input} placeholder="예: HR VIBE 변화의 방향성" value={title} onChange={e => setTitle(e.target.value)} onKeyDown={e => e.key === "Enter" && generate()} />
            <div style={css.fieldLabel}>부제목</div>
            <input style={css.input} placeholder="예: CHO부문 일하는 방식 변화" value={subtitle} onChange={e => setSubtitle(e.target.value)} />
            <div style={css.fieldLabel}>이어브로우</div>
            <input style={css.input} placeholder="예: 2026 AX 내재화 전략" value={eyebrow} onChange={e => setEyebrow(e.target.value)} />
            <div style={css.fieldLabel}>조직명</div>
            <input style={css.input} placeholder="LG PRI CHO부문" value={org} onChange={e => setOrg(e.target.value)} />

            <div style={css.sep} />

            {/* Content */}
            <div style={css.sectionLabel}>콘텐츠 입력 <span style={{ color: "rgba(255,255,255,.2)", fontSize: 9, fontWeight: 400 }}>마크다운 / 개요</span></div>
            <textarea
              style={{ ...css.input, minHeight: 180, lineHeight: 1.65, resize: "vertical" }}
              placeholder={`마크다운 또는 자유 형식 입력\n\n예시:\n## 카드 1: 제목\n설명 텍스트\n\n## 카드 2: 제목\n설명 텍스트`}
              value={content}
              onChange={e => setContent(e.target.value)}
            />
            <div style={{ fontSize: 10, color: "rgba(255,255,255,.2)", textAlign: "right", marginTop: -6, marginBottom: 10 }}>
              {content.length.toLocaleString()}자
            </div>

            {/* Advanced */}
            <button
              onClick={() => setShowAdvanced(v => !v)}
              style={{
                display: "flex", alignItems: "center", gap: 6, background: "none",
                border: "none", cursor: "pointer", color: "rgba(255,255,255,.35)",
                fontSize: 11, fontWeight: 700, letterSpacing: ".1em", textTransform: "uppercase",
                fontFamily: "'Noto Sans KR', system-ui, sans-serif", marginBottom: 10,
                padding: 0,
              }}
            >
              <span style={{ transform: showAdvanced ? "rotate(90deg)" : "none", display: "inline-block", transition: "transform .2s", fontSize: 9 }}>▶</span>
              고급 설정
            </button>

            {showAdvanced && (
              <div>
                <div style={css.fieldLabel}>배경 테마</div>
                <select
                  style={{ ...css.input, cursor: "pointer" }}
                  value={theme} onChange={e => setTheme(e.target.value)}
                >
                  <option value="dark-blue">다크 블루 (기본)</option>
                  <option value="dark-red">다크 레드</option>
                  <option value="light">라이트 모드</option>
                  <option value="dark-black">딥 블랙</option>
                </select>

                <div style={css.fieldLabel}>강조색</div>
                <div style={{ display: "flex", gap: 6, marginBottom: 10 }}>
                  {ACCENTS.map(c => (
                    <div
                      key={c}
                      onClick={() => setAccentColor(c)}
                      style={{
                        width: 26, height: 26, borderRadius: "50%", background: c, cursor: "pointer",
                        border: accentColor === c ? "2px solid #fff" : "2px solid transparent",
                        transform: accentColor === c ? "scale(1.15)" : "none",
                        transition: "all .2s",
                      }}
                    />
                  ))}
                </div>

                <div style={css.fieldLabel}>뒤로가기 URL</div>
                <input style={css.input} placeholder="예: index.html" value={backUrl} onChange={e => setBackUrl(e.target.value)} />

                <div style={css.fieldLabel}>추가 지시사항</div>
                <textarea
                  style={{ ...css.input, minHeight: 60 }}
                  placeholder="예: 탭 형태로 구성, 통계 섹션 추가"
                  value={extra}
                  onChange={e => setExtra(e.target.value)}
                />
              </div>
            )}

            {/* History */}
            {history.length > 0 && (
              <>
                <div style={css.sep} />
                <div style={css.sectionLabel}>최근 생성 기록</div>
                {history.map((h, i) => (
                  <button
                    key={i}
                    onClick={() => {
                      setGeneratedHTML(h.html);
                      setActiveTab("preview");
                      if (iframeRef.current) iframeRef.current.srcdoc = h.html;
                    }}
                    style={{
                      width: "100%", display: "flex", alignItems: "center", gap: 8,
                      padding: "7px 8px", background: "rgba(255,255,255,.04)",
                      border: "1px solid rgba(255,255,255,.06)", borderRadius: 8,
                      cursor: "pointer", marginBottom: 5, textAlign: "left",
                      fontFamily: "'Noto Sans KR', system-ui, sans-serif",
                    }}
                  >
                    <span style={{ fontSize: 10, color: T.red, opacity: .7 }}>◈</span>
                    <span style={{ flex: 1, fontSize: 12, color: "rgba(255,255,255,.55)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{h.title}</span>
                    <span style={{ fontSize: 9, fontWeight: 700, color: "rgba(255,255,255,.2)", letterSpacing: ".05em", textTransform: "uppercase", flexShrink: 0 }}>{h.type}</span>
                  </button>
                ))}
              </>
            )}

            {/* Examples */}
            <div style={css.sep} />
            <div style={css.sectionLabel}>예시 프리셋</div>
            {EXAMPLES.map((ex, i) => (
              <button
                key={i}
                onClick={() => fillExample(ex)}
                style={{
                  width: "100%", display: "flex", alignItems: "center", gap: 8,
                  padding: "8px 10px", background: "rgba(255,255,255,.03)",
                  border: "1px solid rgba(255,255,255,.06)", borderRadius: 8,
                  cursor: "pointer", marginBottom: 6, textAlign: "left",
                  fontFamily: "'Noto Sans KR', system-ui, sans-serif",
                  transition: "all .2s",
                }}
              >
                <span style={{ fontSize: 10, color: T.red, opacity: .6 }}>
                  {PAGE_TYPES.find(p => p.id === ex.type)?.icon}
                </span>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 12, color: "rgba(255,255,255,.7)", fontWeight: 700 }}>{ex.title}</div>
                  <div style={{ fontSize: 10, color: "rgba(255,255,255,.3)", marginTop: 1 }}>{ex.type.toUpperCase()}</div>
                </div>
                <span style={{ fontSize: 10, color: "rgba(165,0,52,.7)" }}>↗</span>
              </button>
            ))}

          </div>

          {/* Generate Button */}
          <div style={css.sidebarFooter}>
            {errorMsg && (
              <div style={{
                padding: "8px 12px", background: "rgba(220,38,38,.2)",
                border: "1px solid rgba(220,38,38,.4)", borderRadius: 8,
                fontSize: 12, color: "#fca5a5", marginBottom: 10, lineHeight: 1.5,
              }}>
                {errorMsg}
              </div>
            )}
            <button
              onClick={generate}
              disabled={isLoading}
              style={{
                width: "100%", padding: 13,
                background: isLoading ? "rgba(165,0,52,.4)" : "linear-gradient(135deg,#A50034 0%,#d4003e 100%)",
                color: "#fff", border: "none", borderRadius: 10,
                fontFamily: "'Noto Sans KR', system-ui, sans-serif",
                fontSize: 14, fontWeight: 700, letterSpacing: ".05em",
                cursor: isLoading ? "not-allowed" : "pointer",
                display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
                transition: "all .2s",
              }}
            >
              {isLoading ? (
                <>
                  <span style={{
                    width: 14, height: 14, border: "2px solid rgba(255,255,255,.3)",
                    borderTopColor: "#fff", borderRadius: "50%",
                    animation: "spin .7s linear infinite", display: "inline-block",
                  }} />
                  <span style={{ fontSize: 12, color: "rgba(255,255,255,.7)" }}>{loadingMsg}</span>
