    "light":     "linear-gradient(135deg,#f8f9fa 0%,#e9ecef 100%)",
    "dark-black":"linear-gradient(165deg,#000000 0%,#0d0d0d 60%,#1a0000 100%)",
  };
  const heroBg = heroBgs[theme] || heroBgs["dark-blue"];
  const bodyBg = theme === "light" ? "#FFFFFF" : "#F9FAFB";

  const typeGuide = {
    portal: `페이지 유형: 포털 메인 (index.html 스타일)
구조: TopBar(fixed) → Hero(dark gradient) → MenuGrid(카드 4열) → StatsRow → Footer
- MenuGrid: grid-template-columns:repeat(4,1fr), 카드에 번호(01~04), FontAwesome 아이콘, 제목, 설명, 링크
