{"returncode":0,"stdout":"<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>EX Intelligence — LG PRI EXG팀 2026</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>

/* ─────────────────────────────────────────────
   LG CHO 포털 빌더 스킬 — 디자인 토큰
   Primary: #A50034 (LG Red)
   Structure: top-bar / hero / main 3단
   Font: Noto Sans KR 전용
───────────────────────────────────────────── */
:root {
  --lg-red:      #A50034;
  --lg-red-dk:   #7A0026;
  --lg-red-lt:   #F9E6EC;
  --lg-red-md:   #D4004A;
  --dark:        #1C1917;
  --dark2:       #2D2926;
  --charcoal:    #3D3935;
  --gray-1:      #5C5855;
  --gray-2:      #8C8A88;
  --gray-3:      #B8B6B4;
  --gray-4:      #E0DEDC;
  --gray-5:      #F2F1EF;
  --gray-6:      #F8F7F6;
  --white:       #FFFFFF;
  --line:        rgba(28,25,23,0.08);
  --line-md:     rgba(28,25,23,0.14);
  --sans:        'Noto Sans KR', sans-serif;
  --radius-sm:   4px;
  --radius-md:   8px;
  --radius-lg:   12px;
  --shadow-sm:   0 1px 4px rgba(0,0,0,0.06), 0 1px 2px rgba(0,0,0,0.04);
  --shadow-md:   0 4px 16px rgba(0,0,0,0.08), 0 2px 6px rgba(0,0,0,0.05);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--sans);
  font-size: 15px;
  line-height: 1.8;
  color: var(--dark);
  background: var(--gray-6);
  overflow-x: hidden;
}

/* ── TOP BAR (LG 레드 상단 바) ── */
.top-bar {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 200;
  height: 4px;
  background: var(--lg-red);
}

/* ── NAVIGATION ── */
nav {
  position: fixed;
  top: 4px; left: 0; right: 0;
  z-index: 100;
  height: 52px;
  background: rgba(255,255,255,0.96);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--line);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 40px;
}
.nav-brand {
  display: flex;
  align-items: center;
  gap: 12px;
}
.nav-logo {
  width: 28px; height: 28px;
  background: var(--lg-red);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}
.nav-logo span {
  font-size: 11px; font-weight: 700;
  color: white; letter-spacing: -0.5px;
}
.nav-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--dark);
  letter-spacing: -0.2px;
}
.nav-sub {
  font-size: 11px;
  color: var(--gray-2);
  font-weight: 400;
  margin-left: 2px;
}
.nav-links {
  display: flex;
  gap: 2px;
  list-style: none;
}
.nav-links a {
  font-size: 12px;
  font-weight: 500;
  color: var(--gray-1);
  text-decoration: none;
  padding: 5px 12px;
  border-radius: var(--radius-sm);
  transition: background .15s, color .15s;
}
.nav-links a:hover {
  background: var(--gray-5);
  color: var(--lg-red);
}

/* ── HERO ── */
.hero {
  min-height: 100vh;
  background: var(--dark);
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0 80px;
  position: relative;
  overflow: hidden;
}
.hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 60% 50% at 70% 40%, rgba(165,0,52,.18) 0%, transparent 65%),
    radial-gradient(ellipse 30% 40% at 10% 80%, rgba(165,0,52,.08) 0%, transparent 55%);
}
.hero::after {
  content: '';
  position: absolute;
  right: 0; top: 0; bottom: 0;
  width: 400px;
  background: linear-gradient(135deg, rgba(165,0,52,.06) 0%, transparent 60%);
  border-left: 1px solid rgba(255,255,255,.04);
}
.hero-content {
  position: relative;
  z-index: 1;
  max-width: 680px;
}
.hero-eyebrow {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 20px;
}
.hero-eyebrow-line {
  width: 24px; height: 1px;
  background: var(--lg-red-md);
}
.hero-eyebrow-text {
  font-size: 11px;
  font-weight: 500;
  color: rgba(165,0,52,.7);
  letter-spacing: 2px;
}
.hero h1 {
  font-size: clamp(36px, 5.5vw, 64px);
  font-weight: 700;
  line-height: 1.15;
  color: #F5F3F0;
  letter-spacing: -1px;
  margin-bottom: 8px;
}
.hero h1 .accent {
  color: var(--lg-red-md);
}
.hero-sub {
  font-size: 15px;
  line-height: 1.75;
  color: rgba(245,243,240,.45);
  max-width: 520px;
  margin-top: 16px;
  font-weight: 300;
}
.hero-kpi {
  display: flex;
  gap: 0;
  margin-top: 48px;
  border: 1px solid rgba(255,255,255,.08);
  border-radius: var(--radius-md);
  overflow: hidden;
  width: fit-content;
}
.hero-kpi-item {
  padding: 18px 28px;
  border-right: 1px solid rgba(255,255,255,.06);
  text-align: center;
}
.hero-kpi-item:last-child { border-right: none; }
.hero-kpi-num {
  display: block;
  font-size: 26px;
  font-weight: 700;
  color: var(--lg-red-md);
  letter-spacing: -0.5px;
  line-height: 1.2;
}
.hero-kpi-label {
  display: block;
  font-size: 11px;
  color: rgba(245,243,240,.35);
  font-weight: 400;
  margin-top: 3px;
  white-space: nowrap;
}

/* ── SECTION WRAPPER ── */
.section-wrap {
  max-width: 960px;
  margin: 0 auto;
  padding: 80px 40px;
}
.section-wrap.wide {
  max-width: 1100px;
}

/* ── SECTION HEADER ── */
.sec-header {
  margin-bottom: 40px;
}
.sec-eyebrow {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 14px;
}
.sec-num {
  font-size: 10px;
  font-weight: 600;
  color: var(--lg-red);
  letter-spacing: 2px;
  background: var(--lg-red-lt);
  padding: 3px 8px;
  border-radius: 3px;
}
.sec-eyebrow-line {
  flex: 1;
  height: 1px;
  background: var(--line);
}
h2.sec-title {
  font-size: clamp(22px, 3vw, 32px);
  font-weight: 700;
  color: var(--dark);
  line-height: 1.3;
  letter-spacing: -0.5px;
  margin-bottom: 8px;
}
.sec-desc {
  font-size: 14px;
  color: var(--gray-1);
  font-weight: 400;
  line-height: 1.6;
}

/* ── BG VARIANTS ── */
.bg-white { background: var(--white); }
.bg-light { background: var(--gray-6); }
.bg-gray  { background: var(--gray-5); }
.bg-dark  { background: var(--dark2); }
.bg-dark .sec-title { color: #F5F3F0 !important; }
.bg-dark .sec-desc  { color: rgba(245,243,240,.45) !important; }
.bg-dark .sec-num   { background: rgba(165,0,52,.25); color: #F08090; }
.bg-dark .sec-eyebrow-line { background: rgba(255,255,255,.06); }

/* ── BODY TEXT ── */
p.body-text {
  font-size: 14.5px;
  line-height: 1.9;
  color: var(--charcoal);
  margin-bottom: 16px;
}
p.body-text strong { font-weight: 600; color: var(--dark); }
.bg-dark p.body-text { color: rgba(245,243,240,.62); }
.bg-dark p.body-text strong { color: rgba(245,243,240,.88); }

/* ── PULL QUOTE ── */
.pull-quote {
  margin: 28px 0;
  padding: 18px 22px;
  border-left: 3px solid var(--lg-red);
  background: var(--lg-red-lt);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}
.pull-quote p {
  font-size: 15.5px;
  font-weight: 500;
  color: var(--lg-red-dk);
  line-height: 1.65;
}
.bg-dark .pull-quote {
  background: rgba(165,0,52,.12);
  border-left-color: rgba(165,0,52,.6);
}
.bg-dark .pull-quote p { color: rgba(245,220,225,.85); }

/* ── CARD ── */
.card {
  background: var(--white);
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  overflow: hidden;
}
.card-header {
  padding: 16px 20px;
  border-bottom: 1px solid var(--gray-4);
  background: var(--gray-6);
}
.card-header-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 2px;
  color: var(--gray-2);
  margin-bottom: 4px;
}
.card-header-title {
  font-size: 15px;
  font-weight: 700;
  color: var(--dark);
}
.card-body { padding: 20px; }

/* ── CIA BOX ── */
.cia-box {
  margin: 24px 0;
  background: var(--dark);
  border-radius: var(--radius-lg);
  border-left: 4px solid var(--lg-red);
  overflow: hidden;
}
.cia-head {
  padding: 14px 20px 12px;
  border-bottom: 1px solid rgba(255,255,255,.06);
  display: flex;
  align-items: center;
  gap: 10px;
}
.cia-badge {
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 2px;
  color: rgba(165,0,52,.7);
  background: rgba(165,0,52,.15);
  padding: 3px 8px;
  border-radius: 3px;
}
.cia-head-title {
  font-size: 13px;
  font-weight: 700;
  color: #F0EDE8;
}
.cia-head-sub {
  font-size: 11px;
  color: rgba(240,237,232,.4);
  font-style: italic;
  margin-left: auto;
}
.cia-body { padding: 16px 20px 18px; }
.cia-body ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.cia-body li {
  font-size: 13px;
  line-height: 1.7;
  color: rgba(240,237,232,.65);
  padding-left: 16px;
  position: relative;
}
.cia-body li::before {
  content: '▪';
  position: absolute;
  left: 0;
  color: var(--lg-red);
  font-size: 10px;
  top: 3px;
}
.cia-body li strong { color: #F0EDE8; font-weight: 600; }

/* ── BENCH BOX ── */
.bench-box {
  margin: 24px 0;
  background: #0E1E38;
  border-radius: var(--radius-lg);
  border-left: 4px solid #3A6AAA;
  overflow: hidden;
}
.bench-head {
  padding: 14px 20px 12px;
  border-bottom: 1px solid rgba(255,255,255,.06);
  display: flex;
  align-items: center;
  gap: 10px;
}
.bench-badge {
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 2px;
  color: #7AAAD4;
  background: rgba(58,106,170,.2);
  padding: 3px 8px;
  border-radius: 3px;
}
.bench-head-title { font-size: 13px; font-weight: 700; color: #D4E8F8; }
.bench-head-sub   { font-size: 11px; color: rgba(212,232,248,.4); font-style: italic; margin-left: auto; }
.bench-body { padding: 16px 20px 18px; }
.bench-body ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.bench-body li {
  font-size: 13px; line-height: 1.7;
  color: rgba(212,232,248,.65);
  padding-left: 16px; position: relative;
}
.bench-body li::before { content: '▶'; position: absolute; left: 0; color: #3A6AAA; font-size: 9px; top: 4px; }
.bench-body li strong { color: #D4E8F8; font-weight: 600; }

/* ── THEORY BOX ── */
.theory-box {
  margin: 24px 0;
  background: #0A2016;
  border-radius: var(--radius-lg);
  border-left: 4px solid #1D6A4A;
  overflow: hidden;
}
.theory-head {
  padding: 14px 20px 12px;
  border-bottom: 1px solid rgba(255,255,255,.05);
  display: flex;
  align-items: center;
  gap: 10px;
}
.theory-badge {
  font-size: 9px; font-weight: 600; letter-spacing: 2px;
  color: #4AAA8A; background: rgba(29,106,74,.2);
  padding: 3px 8px; border-radius: 3px;
}
.theory-head-title { font-size: 13px; font-weight: 700; color: #C0EAD8; }
.theory-stat {
  margin-left: auto;
  font-size: 11px; font-weight: 600;
  color: #4AAA8A;
  background: rgba(29,106,74,.15);
  padding: 2px 8px; border-radius: 3px;
}
.theory-body { padding: 16px 20px 18px; }
