  font-weight: 400;
  margin-top: 3px;
  white-space: nowrap;
}

/* ── SECTION WRAPPER ── */
.section-wrap {
  max-width: 960px;
  margin: 0 auto;
  padding: 80px 40px;
}
.section-wrap.wide {
  max-width: 1100px;
}

/* ── SECTION HEADER ── */
.sec-header {
  margin-bottom: 40px;
}
.sec-eyebrow {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 14px;
}
.sec-num {
  font-size: 10px;
  font-weight: 600;
  color: var(--lg-red);
  letter-spacing: 2px;
  background: var(--lg-red-lt);
  padding: 3px 8px;
  border-radius: 3px;
}
.sec-eyebrow-line {
  flex: 1;
  height: 1px;
  background: var(--line);
}
h2.sec-title {
  font-size: clamp(22px, 3vw, 32px);
  font-weight: 700;
  color: var(--dark);
  line-height: 1.3;
  letter-spacing: -0.5px;
  margin-bottom: 8px;
}
.sec-desc {
  font-size: 14px;
  color: var(--gray-1);
  font-weight: 400;
  line-height: 1.6;
}

/* ── BG VARIANTS ── */
.bg-white { background: var(--white); }
.bg-light { background: var(--gray-6); }
.bg-gray  { background: var(--gray-5); }
.bg-dark  { background: var(--dark2); }
.bg-dark .sec-title { color: #F5F3F0 !important; }
.bg-dark .sec-desc  { color: rgba(245,243,240,.45) !important; }
.bg-dark .sec-num   { background: rgba(165,0,52,.25); color: #F08090; }
.bg-dark .sec-eyebrow-line { background: rgba(255,255,255,.06); }

/* ── BODY TEXT ── */
p.body-text {
  font-size: 14.5px;
  line-height: 1.9;
  color: var(--charcoal);
  margin-bottom: 16px;
}
p.body-text strong { font-weight: 600; color: var(--dark); }
.bg-dark p.body-text { color: rgba(245,243,240,.62); }
.bg-dark p.body-text strong { color: rgba(245,243,240,.88); }

/* ── PULL QUOTE ── */
.pull-quote {
  margin: 28px 0;
  padding: 18px 22px;
  border-left: 3px solid var(--lg-red);
  background: var(--lg-red-lt);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}
.pull-quote p {
  font-size: 15.5px;
  font-weight: 500;
  color: var(--lg-red-dk);
  line-height: 1.65;
}
.bg-dark .pull-quote {
  background: rgba(165,0,52,.12);
  border-left-color: rgba(165,0,52,.6);
}
.bg-dark .pull-quote p { color: rgba(245,220,225,.85); }

/* ── CARD ── */
.card {
  background: var(--white);
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  overflow: hidden;
}
.card-header {
  padding: 16px 20px;
  border-bottom: 1px solid var(--gray-4);
  background: var(--gray-6);
}
.card-header-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 2px;
  color: var(--gray-2);
  margin-bottom: 4px;
}
.card-header-title {
  font-size: 15px;
  font-weight: 700;
  color: var(--dark);
}
.card-body { padding: 20px; }

/* ── CIA BOX ── */
.cia-box {
  margin: 24px 0;
  background: var(--dark);
  border-radius: var(--radius-lg);
  border-left: 4px solid var(--lg-red);
  overflow: hidden;
}
.cia-head {
  padding: 14px 20px 12px;
  border-bottom: 1px solid rgba(255,255,255,.06);
  display: flex;
  align-items: center;
  gap: 10px;
}
.cia-badge {
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 2px;
  color: rgba(165,0,52,.7);
  background: rgba(165,0,52,.15);
  padding: 3px 8px;
  border-radius: 3px;
}
.cia-head-title {
  font-size: 13px;
  font-weight: 700;
  color: #F0EDE8;
}
.cia-head-sub {
  font-size: 11px;
  color: rgba(240,237,232,.4);
  font-style: italic;
  margin-left: auto;
}
.cia-body { padding: 16px 20px 18px; }
.cia-body ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.cia-body li {
  font-size: 13px;
  line-height: 1.7;
  color: rgba(240,237,232,.65);
  padding-left: 16px;
  position: relative;
}
.cia-body li::before {
  content: '▪';
  position: absolute;
  left: 0;
  color: var(--lg-red);
  font-size: 10px;
  top: 3px;
}
.cia-body li strong { color: #F0EDE8; font-weight: 600; }

/* ── BENCH BOX ── */
.bench-box {
  margin: 24px 0;
  background: #0E1E38;
  border-radius: var(--radius-lg);
  border-left: 4px solid #3A6AAA;
  overflow: hidden;
}
.bench-head {
  padding: 14px 20px 12px;
  border-bottom: 1px solid rgba(255,255,255,.06);
  display: flex;
  align-items: center;
  gap: 10px;
}
.bench-badge {
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 2px;
  color: #7AAAD4;
  background: rgba(58,106,170,.2);
  padding: 3px 8px;
  border-radius: 3px;
}
.bench-head-title { font-size: 13px; font-weight: 700; color: #D4E8F8; }
.bench-head-sub   { font-size: 11px; color: rgba(212,232,248,.4); font-style: italic; margin-left: auto; }
.bench-body { padding: 16px 20px 18px; }
.bench-body ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.bench-body li {
  font-size: 13px; line-height: 1.7;
  color: rgba(212,232,248,.65);
  padding-left: 16px; position: relative;
}
.bench-body li::before { content: '▶'; position: absolute; left: 0; color: #3A6AAA; font-size: 9px; top: 4px; }
.bench-body li strong { color: #D4E8F8; font-weight: 600; }

/* ── THEORY BOX ── */
.theory-box {
  margin: 24px 0;
  background: #0A2016;
  border-radius: var(--radius-lg);
  border-left: 4px solid #1D6A4A;
  overflow: hidden;
}
.theory-head {
  padding: 14px 20px 12px;
  border-bottom: 1px solid rgba(255,255,255,.05);
  display: flex;
  align-items: center;
  gap: 10px;
}
.theory-badge {
  font-size: 9px; font-weight: 600; letter-spacing: 2px;
  color: #4AAA8A; background: rgba(29,106,74,.2);
  padding: 3px 8px; border-radius: 3px;
}
.theory-head-title { font-size: 13px; font-weight: 700; color: #C0EAD8; }
.theory-stat {
  margin-left: auto;
  font-size: 11px; font-weight: 600;
  color: #4AAA8A;
  background: rgba(29,106,74,.15);
  padding: 2px 8px; border-radius: 3px;
}
.theory-body { padding: 16px 20px 18px; }
.theory-body ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
.theory-body li {
  font-size: 13px; line-height: 1.7;
  color: rgba(192,234,216,.65);
  padding-left: 16px; position: relative;
}
.theory-body li::before { content: '◆'; position: absolute; left: 0; color: #1D6A4A; font-size: 9px; top: 4px; }
.theory-body li strong { color: #C0EAD8; font-weight: 600; }

/* ── DBOX (레드 액센트 리스트) ── */
.dbox {
  margin: 20px 0;
  padding: 16px 20px;
  border: 1px solid rgba(165,0,52,.15);
  border-left: 3px solid var(--lg-red);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  background: var(--white);
}
.dbox-label {
  font-size: 10px; font-weight: 600;
  letter-spacing: 1.5px; color: var(--lg-red);
  margin-bottom: 10px;
}
.dbox ul { list-style: none; display: flex; flex-direction: column; gap: 6px; }
.dbox li {
  font-size: 13px; line-height: 1.75;
  color: var(--charcoal);
  padding-left: 14px; position: relative;
}
.dbox li::before { content: '•'; position: absolute; left: 2px; color: var(--lg-red); }
.dbox li strong { font-weight: 600; color: var(--dark); }

/* ── KPI STRIP ── */
.kpi-strip {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin: 28px 0;
  background: var(--white);
  box-shadow: var(--shadow-sm);
}
.kpi-item {
  padding: 20px 16px;
  border-right: 1px solid var(--gray-4);
  text-align: center;
}
.kpi-item:last-child { border-right: none; }
.kpi-num {
  display: block;
  font-size: 26px; font-weight: 700;
  color: var(--lg-red);
  letter-spacing: -0.5px;
  line-height: 1.2;
  margin-bottom: 4px;
}
.kpi-label {
  font-size: 11px; color: var(--gray-1);
  line-height: 1.45; font-weight: 400;
}

/* ── 3-TIER GRID ── */
.tier-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  margin: 28px 0;
}
.tier-card {
  border-radius: var(--radius-lg);
  border: 1px solid var(--gray-4);
  background: var(--white);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
}
.tier-head {
  padding: 14px 16px 12px;
}
.tier-card.leader .tier-head { background: #1A2C58; border-bottom: 2px solid #3A5A9A; }
.tier-card.exec   .tier-head { background: var(--dark); border-bottom: 2px solid var(--lg-red); }
.tier-card.hr     .tier-head { background: #0A2A1A; border-bottom: 2px solid #1D6A4A; }
.tier-role { font-size: 13px; font-weight: 700; color: #F5F3F0; margin-bottom: 2px; }
.tier-cia  { font-size: 10px; color: rgba(245,243,240,.4); font-weight: 400; }
.tier-body { padding: 16px; }
.tier-q {
  font-size: 14px; font-weight: 700;
  margin-bottom: 10px; padding-bottom: 10px;
  border-bottom: 1px dashed var(--gray-4);
}
.tier-card.leader .tier-q { color: #1A2C58; }
.tier-card.exec   .tier-q { color: var(--lg-red-dk); }
.tier-card.hr     .tier-q { color: #085041; }
.tier-section { margin-bottom: 10px; }
.tier-section-label {
  font-size: 9px; font-weight: 600;
  letter-spacing: 1.5px; margin-bottom: 5px;
}
.tier-card.leader .tier-section-label { color: #3A5A9A; }
.tier-card.exec   .tier-section-label { color: var(--lg-red); }
.tier-card.hr     .tier-section-label { color: #1D6A4A; }
.tier-text { font-size: 12.5px; line-height: 1.65; color: var(--gray-1); }
.tier-stat {
  font-size: 11px; line-height: 1.5;
  color: var(--gray-2); font-style: italic;
  padding: 8px 10px;
  background: var(--gray-5);
  border-radius: var(--radius-sm);
  margin-top: 10px;
}

/* ── 3-LAYER FLOW ── */
.layer-flow {
  display: grid;
  grid-template-columns: 1fr auto 1fr auto 1fr;
  align-items: stretch;
  gap: 0;
  margin: 24px 0;
}
.layer-card {
  border-radius: var(--radius-md);
  padding: 18px 16px;
  border: 1px solid var(--gray-4);
}
.layer-card.l1 { background: #F0FAF6; border-color: rgba(29,106,74,.3); }
.layer-card.l2 { background: #F0F4FB; border-color: rgba(58,106,170,.3); }
.layer-card.l3 { background: var(--lg-red-lt); border-color: rgba(165,0,52,.25); }
.layer-tag {
  font-size: 9.5px; font-weight: 600;
  letter-spacing: 1.5px; margin-bottom: 6px;
}
.layer-card.l1 .layer-tag { color: #1D6A4A; }
.layer-card.l2 .layer-tag { color: #3A5A9A; }
.layer-card.l3 .layer-tag { color: var(--lg-red); }
.layer-title { font-size: 14px; font-weight: 700; margin-bottom: 6px; }
.layer-card.l1 .layer-title { color: #085041; }
.layer-card.l2 .layer-title { color: #1A2C58; }
.layer-card.l3 .layer-title { color: var(--lg-red-dk); }
.layer-desc { font-size: 12px; line-height: 1.65; color: var(--gray-1); }
.layer-arr {
  display: flex; align-items: center;
  padding: 0 10px; color: var(--gray-3);
  font-size: 18px; font-weight: 300;
}

/* ── THEORY GRID ── */
.theory-matrix {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  margin: 24px 0;
}
.th-card {
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-md);
  padding: 16px;
  background: var(--white);
  box-shadow: var(--shadow-sm);
}
.th-abbr {
  font-size: 10px; font-weight: 600;
  letter-spacing: 1.5px; color: var(--lg-red);
  background: var(--lg-red-lt);
  padding: 2px 7px; border-radius: 3px;
  display: inline-block; margin-bottom: 8px;
}
.th-name { font-size: 14px; font-weight: 700; color: var(--dark); margin-bottom: 2px; }
.th-scholar { font-size: 11px; color: var(--gray-2); margin-bottom: 8px; }
.th-stat { font-size: 12px; font-weight: 600; color: var(--lg-red); margin-bottom: 8px; }
.th-apply { font-size: 12.5px; line-height: 1.65; color: var(--gray-1); }

/* ── MILESTONE ── */
.milestone {
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin: 24px 0;
  background: var(--white);
  box-shadow: var(--shadow-sm);
}
.ms-row {
  display: grid;
  grid-template-columns: 110px 1fr;
}
.ms-row + .ms-row { border-top: 1px solid var(--gray-4); }
.ms-tag {
  padding: 18px 14px;
  background: var(--dark);
  display: flex; flex-direction: column;
  justify-content: center; gap: 3px;
  border-right: 3px solid var(--lg-red);
}
.ms-m { font-size: 9.5px; font-weight: 500; color: rgba(245,243,240,.3); letter-spacing: 1px; }
.ms-date { font-size: 13px; font-weight: 700; color: #F5F3F0; }
.ms-body { padding: 16px 18px; }
.ms-title { font-size: 13.5px; font-weight: 700; color: var(--dark); margin-bottom: 5px; }
.ms-desc { font-size: 12.5px; line-height: 1.7; color: var(--gray-1); }

/* ── FAQ ── */
.faq-item {
  padding: 20px 0;
  border-bottom: 1px solid var(--gray-4);
}
.faq-item:last-child { border-bottom: none; }
.faq-q {
  font-size: 15px; font-weight: 700; color: var(--dark);
  margin-bottom: 8px;
  padding-left: 20px; position: relative;
}
.faq-q::before {
  content: 'Q';
  position: absolute; left: 0;
  color: var(--lg-red);
  font-size: 13px; font-weight: 700;
  background: var(--lg-red-lt);
  width: 18px; height: 18px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 3px; top: 2px;
  line-height: 1;
  text-indent: 0;
}
.faq-a { font-size: 14px; line-height: 1.85; color: var(--charcoal); }

/* ── PRESS RELEASE CARD ── */
.press-card {
  background: var(--white);
  border: 1px solid var(--gray-4);
  border-radius: var(--radius-lg);
  padding: 28px 32px;
  margin: 28px 0;
  box-shadow: var(--shadow-md);
}
.press-date {
  font-size: 10px; font-weight: 600;
  letter-spacing: 2px; color: var(--gray-2);
  margin-bottom: 12px;
}
.press-title {
  font-size: 22px; font-weight: 700;
  color: var(--dark);
  line-height: 1.35; margin-bottom: 6px;
  letter-spacing: -0.3px;
}
.press-subtitle { font-size: 13px; color: var(--gray-2); margin-bottom: 18px; }
.press-body { font-size: 14px; line-height: 1.85; color: var(--charcoal); }
.press-highlight {
  margin-top: 18px;
  padding: 14px 18px;
  border-left: 3px solid var(--lg-red);
  background: var(--lg-red-lt);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}
.press-highlight p {
  font-size: 14.5px; font-weight: 500;
  color: var(--lg-red-dk); line-height: 1.65;
}

/* ── CLOSING ── */
.closing {
  background: var(--dark);
  padding: 80px 0 60px;
}
.closing .section-wrap { text-align: center; }
.close-eyebrow {
  font-size: 10px; font-weight: 600;
  letter-spacing: 3px; color: rgba(245,243,240,.2);
  margin-bottom: 20px;
}
.close-title {
  font-size: clamp(26px, 3.5vw, 42px);
  font-weight: 700; color: #F5F3F0;
  line-height: 1.25; margin-bottom: 24px;
  letter-spacing: -0.5px;
}
.close-body {
  font-size: 14px; line-height: 1.9;
  color: rgba(245,243,240,.48);
  max-width: 540px; margin: 0 auto 16px;
}
.close-quote {
  font-size: 17px; font-weight: 500;
  color: rgba(165,0,52,.7);
  margin-top: 36px;
  line-height: 1.6;
}

/* ── FOOTER ── */
footer {
  background: var(--charcoal);
  padding: 20px 40px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-top: 1px solid rgba(255,255,255,.04);
}
footer span {
  font-size: 11px; color: rgba(255,255,255,.22);
  font-weight: 400;
}

/* ── DIVIDER ── */
.divider { height: 1px; background: var(--line); margin: 40px 0; }

/* ── REVEAL ── */
.reveal {
  opacity: 0;
  transform: translateY(16px);
  transition: opacity .55s ease, transform .55s ease;
}
.reveal.visible { opacity: 1; transform: translateY(0); }

@media(max-width: 768px) {
  nav { padding: 0 16px; }
  .nav-links { display: none; }
  .hero { padding: 72px 24px 48px; min-height: auto; }
  .section-wrap { padding: 52px 20px; }
  .tier-grid, .theory-matrix { grid-template-columns: 1fr; }
  .kpi-strip { grid-template-columns: 1fr 1fr; }
  .layer-flow { grid-template-columns: 1fr; }
  .layer-arr { display: none; }
  .hero-kpi { flex-wrap: wrap; gap: 0; }
  footer { flex-direction: column; gap: 4px; text-align: center; }
}
</style>
